#!/usr/bin/env bpftrace
// runqlat.bt	CPU scheduler run queue latency as a histogram.
// 		For Linux, uses bpftrace, eBPF.
//
// Example of usage:
//
// # ./runqlat.bt
// Attaching 5 probes...
// Tracing CPU scheduler... Hit Ctrl-C to end.
//
// @usecs:
// [0]                    1 |                                                    |
// [1]                   11 |@@                                                  |
// [2, 4)                16 |@@@                                                 |
// [4, 8)                43 |@@@@@@@@@@                                          |
// [8, 16)              134 |@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@                     |
// [16, 32)             220 |@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@|
// [32, 64)             117 |@@@@@@@@@@@@@@@@@@@@@@@@@@@                         |
// [64, 128)             84 |@@@@@@@@@@@@@@@@@@@                                 |
// [128, 256)            10 |@@                                                  |
//
// This is a bpftrace version of the bcc tool of the same name.
// The bcc version provides options to customize the output.
//
// Copyright 2018 Netflix, Inc.
//
// 17-Sep-2018	Brendan Gregg	Created this.

#ifndef BPFTRACE_HAVE_BTF
#include <linux/sched.h>
#else
// With BTF providing types, full headers are not needed.
// We only need to supply the preprocessor defines used in this script.
// TASK_RUNNING is not arch-dependant and has not changed in the linux
// git history (it is not part of the stable API though)
#define TASK_RUNNING 0
#endif

BEGIN
{
  printf("Tracing CPU scheduler... Hit Ctrl-C to end.\n");
}

tracepoint:sched:sched_wakeup,
tracepoint:sched:sched_wakeup_new
{
  @qtime[args.pid] = nsecs;
}

tracepoint:sched:sched_switch
{
  if (args.prev_state == TASK_RUNNING) {
    @qtime[args.prev_pid] = nsecs;
  }
  // Ignore the idle task
  if (args.next_pid == 0) {
    return;
  }

  $ns = @qtime[args.next_pid];
  if ($ns) {
    @usecs = hist((nsecs - $ns) / 1000);
    // Swallowing deletion failures as they are expected
    delete(@qtime[args.next_pid]);
  }
}

END
{
  clear(@qtime);
}

#!/usr/bin/env bpftrace
// tcpretrans.bt Trace or count TCP retransmits
//               For Linux, uses bpftrace and eBPF.
//
// This uses dynamic tracing of kernel functions, and will need to be updated
// to match kernel changes.
//
// Example of usage:
//
// # ./tcpretrans.bt
// TIME     PID               LADDR:LPORT           RADDR:RPORT  STATE
// 01:55:05 0        10.153.223.157:22       69.53.245.40:34619  ESTABLISHED
// 01:55:05 0        10.153.223.157:22       69.53.245.40:34619  ESTABLISHED
// 01:55:17 0        10.153.223.157:22       69.53.245.40:22957  ESTABLISHED
// [...]
//
// This output shows three TCP retransmits, the first two were for an IPv4
// connection from 10.153.223.157 port 22 to 69.53.245.40 port 34619. The TCP
// state was "ESTABLISHED" at the time of the retransmit.
//
// Retransmits are usually a sign of poor network health, and this tool is
// useful for their investigation. Unlike using tcpdump, this tool has very
// low overhead, as it only traces the retransmit function.
//
// This is a bpftrace version of the bcc tool of the same name.
// It doesn't support tracking TLPs.
//
// Copyright (c) 2018 Dale Hamel.
//
// 23-Nov-2018  Dale Hamel      created this.

#ifndef BPFTRACE_HAVE_BTF
#include <linux/socket.h>
#include <net/sock.h>
#else
// With BTF providing types, socket headers are not needed.
// We only need to supply the preprocessor defines in this script.
// AF_INET/AF_INET6 are part of the stable arch-independent Linux ABI
#define AF_INET   2
#define AF_INET6 10
#endif

BEGIN
{
  printf("Tracing tcp retransmits. Hit Ctrl-C to end.\n");
  printf("%-8s %-8s %20s %21s %6s\n",
         "TIME", "PID", "LADDR:LPORT", "RADDR:RPORT", "STATE");

  // See include/net/tcp_states.h:
  @tcp_states[(uint64)1] = "ESTABLISHED";
  @tcp_states[2] = "SYN_SENT";
  @tcp_states[3] = "SYN_RECV";
  @tcp_states[4] = "FIN_WAIT1";
  @tcp_states[5] = "FIN_WAIT2";
  @tcp_states[6] = "TIME_WAIT";
  @tcp_states[7] = "CLOSE";
  @tcp_states[8] = "CLOSE_WAIT";
  @tcp_states[9] = "LAST_ACK";
  @tcp_states[10] = "LISTEN";
  @tcp_states[11] = "CLOSING";
  @tcp_states[12] = "NEW_SYN_RECV";
}

kprobe:tcp_retransmit_skb
{
  $sk = (struct sock *)arg0;
  $inet_family = $sk->__sk_common.skc_family;

  if ($inet_family == AF_INET || $inet_family == AF_INET6) {
    // initialize variable type:
    $daddr = ntop(0);
    $saddr = ntop(0);
    if ($inet_family == AF_INET) {
      $daddr = ntop($sk->__sk_common.skc_daddr);
      $saddr = ntop($sk->__sk_common.skc_rcv_saddr);
    }
    $lport = $sk->__sk_common.skc_num;
    $dport = $sk->__sk_common.skc_dport;

    // Destination port is big endian, it must be flipped
    $dport = bswap($dport);

    $state = $sk->__sk_common.skc_state;
    $statestr = @tcp_states[$state];

    time("%H:%M:%S ");
    printf("%-8d %14s:%-6d %14s:%-6d %6s\n",
           pid, $saddr, $lport, $daddr, $dport, $statestr);
  }
}

END
{
  clear(@tcp_states);
}

#!/usr/bin/env bpftrace
// capable	Trace security capability checks (cap_capable()).
// 		For Linux, uses bpftrace and eBPF.
//
// Example of usage:
//
// # ./capable.bt
// TIME      UID    PID    COMM             CAP  NAME                 AUDIT
// 22:11:23  114    2676   snmpd            12   CAP_NET_ADMIN        1
// 22:11:23  0      6990   run              24   CAP_SYS_RESOURCE     1
// 22:11:23  0      7003   chmod            3    CAP_FOWNER           1
// 22:11:23  0      7003   chmod            4    CAP_FSETID           1
//
// This can be useful for general debugging, and also security enforcement:
// determining a whitelist of capabilities an application needs.
//
// This is a bpftrace version of the bcc tool of the same name.
// The bcc version provides options to customize the output.
//
// Copyright 2018 Netflix, Inc.
//
// 08-Sep-2018	Brendan Gregg	Created this.

BEGIN
{
  printf("Tracing cap_capable syscalls... Hit Ctrl-C to end.\n");
  printf("%-9s %-6s %-6s %-16s %-4s %-20s AUDIT\n",
         "TIME", "UID", "PID", "COMM", "CAP", "NAME");
  @cap[(uint64)0] = "CAP_CHOWN";
  @cap[1] = "CAP_DAC_OVERRIDE";
  @cap[2] = "CAP_DAC_READ_SEARCH";
  @cap[3] = "CAP_FOWNER";
  @cap[4] = "CAP_FSETID";
  @cap[5] = "CAP_KILL";
  @cap[6] = "CAP_SETGID";
  @cap[7] = "CAP_SETUID";
  @cap[8] = "CAP_SETPCAP";
  @cap[9] = "CAP_LINUX_IMMUTABLE";
  @cap[10] = "CAP_NET_BIND_SERVICE";
  @cap[11] = "CAP_NET_BROADCAST";
  @cap[12] = "CAP_NET_ADMIN";
  @cap[13] = "CAP_NET_RAW";
  @cap[14] = "CAP_IPC_LOCK";
  @cap[15] = "CAP_IPC_OWNER";
  @cap[16] = "CAP_SYS_MODULE";
  @cap[17] = "CAP_SYS_RAWIO";
  @cap[18] = "CAP_SYS_CHROOT";
  @cap[19] = "CAP_SYS_PTRACE";
  @cap[20] = "CAP_SYS_PACCT";
  @cap[21] = "CAP_SYS_ADMIN";
  @cap[22] = "CAP_SYS_BOOT";
  @cap[23] = "CAP_SYS_NICE";
  @cap[24] = "CAP_SYS_RESOURCE";
  @cap[25] = "CAP_SYS_TIME";
  @cap[26] = "CAP_SYS_TTY_CONFIG";
  @cap[27] = "CAP_MKNOD";
  @cap[28] = "CAP_LEASE";
  @cap[29] = "CAP_AUDIT_WRITE";
  @cap[30] = "CAP_AUDIT_CONTROL";
  @cap[31] = "CAP_SETFCAP";
  @cap[32] = "CAP_MAC_OVERRIDE";
  @cap[33] = "CAP_MAC_ADMIN";
  @cap[34] = "CAP_SYSLOG";
  @cap[35] = "CAP_WAKE_ALARM";
  @cap[36] = "CAP_BLOCK_SUSPEND";
  @cap[37] = "CAP_AUDIT_READ";
  @cap[38] = "CAP_PERFMON";
  @cap[39] = "CAP_BPF";
  @cap[40] = "CAP_CHECKPOINT_RESTORE";
}

kprobe:cap_capable
{
  $cap = arg2;
  $audit = arg3;
  time("%H:%M:%S  ");
  printf("%-6d %-6d %-16s %-4d %-20s %d\n", uid, pid, comm, $cap, @cap[$cap], $audit);
}

END
{
  clear(@cap);
}

